void fill_screen(UINT32 *base, char pattern)
{
    register int i = 0;
    register UINT32 *location = base;

    /* could write */

    while (i++ < BYTES_PER_SCREEN / 4)
        *(location++) = pattern;
}

void print_splash(UINT8 *base)
{
    UINT16 row;
    UINT16 bit;
    UINT16 chunk;
    UINT8 chunk_buffer[SPLASH_HEIGHT * 4];

    /* black background */
    fill_screen((UINT32 *)base, 0xff);

    /* Print Geo fancy text in chunks */
    for (chunk = 0; chunk < SPRITE_CHUNK_COUNT; chunk++)
    {
        const UINT16 dst_col = (UINT16)(chunk << 5);
        UINT16 remaining_pixels = (UINT16)(SPRITE_WIDTH - dst_col);

        if (remaining_pixels > 32)
            remaining_pixels = 32;

        for (row = 0; row < SPRITE_HEIGHT; row++)
        {
            UINT8 *dst_row = chunk_buffer + (row * 4);
            dst_row[0] = 0;
            dst_row[1] = 0;
            dst_row[2] = 0;
            dst_row[3] = 0;

            for (bit = 0; bit < remaining_pixels; bit++)
            {
                UINT16 x = (UINT16)(dst_col + bit);
                UINT16 src_index;
                UINT8 src_mask;
                UINT8 src_byte;

                if (SPRITE_USE_PAGE_PACKED)
                {
                    /* Page-packed format (width * ceil(height/8)) */
                    src_index = (UINT16)(((row >> 3) * SPRITE_WIDTH) + x);
                    src_mask = (UINT8)(1 << (row & 7));
                }
                else
                {
                    src_index = (UINT16)(row * SPRITE_ROW_BYTES + (x >> 3));
                    src_mask = (UINT8)(0x80 >> (x & 7));
                }

                src_byte = (src_index < sizeof(SPLASH_MAP)) ? SPLASH_MAP[src_index] : 0;
                if ((src_byte & src_mask) != 0)
                    dst_row[bit >> 3] |= (UINT8)(0x80 >> (bit & 7));
            }
        }

        plot_bitmap_32(base, SPRITE_START_ROW, (INT16)(SPRITE_START_COL + dst_col), (const UINT32 *)chunk_buffer, SPRITE_HEIGHT);
    }

    /* Two stacked 64x32 overlays, 32px in from the bitmap's right edge. */
    clear_region((UINT32 *)base, SPRITE_RECT_TOP, SPRITE_RECT_COL, 32, 80);
    clear_region((UINT32 *)base, (INT16)(SPRITE_RECT_TOP + 80), SPRITE_RECT_COL, 32, 80);

    plot_string(base, 60, SCREEN_WIDTH / 2 - 100, " Space to switch buttons, enter to select");

    plot_triangle((UINT32 *)base, 399, 639, 56, 56, 2);
}


#define SCREEN_WIDTH 640
#define SCREEN_HEIGHT 400

void make_screen_bmap(UINT8 *base)
{
    FILE *fp = fopen("screen.txt", "w");
    if (fp != NULL)
    {
        int i;
        /* Print first 100 bytes as debug */
        for (i = 0; i < 100; i++)
        {
            fprintf(fp, "%02x", base[i]);
        }
        fprintf(fp, "\n\n");
        /* Print rest of screen */
        for (i = 100; i < BYTES_PER_SCREEN; i++)
        {
            fprintf(fp, "%02x", base[i]);
        }
        fclose(fp);
    }
}